const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;

if (!tenantId || !automationId) {
  return [{ json: { success: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, valid: true } }];

const info = $('03. Chercher infos').first().json;
const adminRow = $input.first().json;
const adminEmail = adminRow?.email || null;
const delais = { simple: '24 heures', intermediaire: '48 heures', avance: '72 heures' };
const delai = delais[info.complexity] || '48 heures';

return [{ json: {
  automationNom: info.nom,
  clientName: info.client_name,
  complexity: info.complexity,
  setupPrice: info.setup_price,
  monthlyPrice: info.monthly_price,
  delai,
  adminEmail
} }];

const data = $('06. Preparer notif').first().json;

return [{ json: {
  success: true,
  data: {
    message: `Demande envoyee ! Vous serez recontacte sous ${data.delai} pour l'activation de ${data.automationNom}.`,
    delai: data.delai,
    automationNom: data.automationNom
  }
} }];
